1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
16	type Damage = { itemType: string; amount: number };
17	type Incident = { cause: string; damages: Damage[] };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
20	type Step = QuoteStep | ClaimStep;
21	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
22	
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const HIGH_ENCHANTMENT_COVERAGE_THRESHOLD = 8;
25	const HIGH_ENCHANTMENT_COVERAGE_RATE = 0.5;
26	
27	const reimbursableAmount = (item: Item, damageAmount: number): number => {
28	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_COVERAGE_THRESHOLD) {
29	    return damageAmount * HIGH_ENCHANTMENT_COVERAGE_RATE;
30	  }
31	  return damageAmount;
32	};
33	
34	const claimStep = (step: ClaimStep, policyItems: Item[]): { payout: number } => {
35	  const payout = step.incident.damages.reduce((sum, d) => {
36	    const item = policyItems.find((i) => i.type === d.itemType) ?? { type: d.itemType };
37	    const reimbursable = reimbursableAmount(item, d.amount);
38	    return sum + (reimbursable - DEDUCTIBLE_PER_DAMAGE);
39	  }, 0);
40	  return { payout };
41	};
42	
43	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
44	
45	const BLOCK_SIZE = 3;
46	const COMPONENT_BLOCK_PRICE = 60;
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const sumItemBasePremiums = (items: Item[]): number =>
51	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
52	
53	const groupByType = (items: Item[]): Map<string, Item[]> => {
54	  const groups = new Map<string, Item[]>();
55	  for (const item of items) {
56	    const group = groups.get(item.type) ?? [];
57	    group.push(item);
58	    groups.set(item.type, group);
59	  }
60	  return groups;
61	};
62	
63	const priceComponentGroup = (group: Item[]): number =>
64	  group.length === BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : sumItemBasePremiums(group);
65	
66	const computeBasePremium = (items: Item[]): number => {
67	  const components = items.filter(isComponent);
68	  const nonComponents = items.filter((item) => !isComponent(item));
69	  const componentGroups = [...groupByType(components).values()];
70	  const componentTotal = componentGroups.reduce(
71	    (sum, group) => sum + priceComponentGroup(group),
72	    0,
73	  );
74	  return sumItemBasePremiums(nonComponents) + componentTotal;
75	};
76	
77	const CURSE_SURCHARGE_RATE = 0.5;
78	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
79	const HIGH_ENCHANTMENT_THRESHOLD = 5;
80	
81	const itemSurcharge = (item: Item): number => {
82	  const base = itemBasePremium(item);
83	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
84	  const enchantment =
85	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
86	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
87	      : 0;
88	  return curse + enchantment;
89	};
90	
91	const sumItemSurcharges = (items: Item[]): number =>
92	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
93	
94	const LOYALTY_DISCOUNT_RATE = 0.2;
95	const LOYALTY_THRESHOLD_YEARS = 2;
96	
97	type Customer = { yearsWithMHPCO: number };
98	type PolicyContext = { customer: Customer; contractIndex: number };
99	
100	const loyaltyDiscount = (base: number, customer: Customer): number =>
101	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
102	
103	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
104	
105	const followUpDiscount = (base: number, contractIndex: number): number =>
106	  contractIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
107	
108	const sumPolicyDiscounts = (base: number, ctx: PolicyContext): number =>
109	  loyaltyDiscount(base, ctx.customer) + followUpDiscount(base, ctx.contractIndex);
110	
111	const sumPolicySurcharges = (base: number): number => base * FIRST_INSURANCE_RATE;
112	
113	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
114	  const base = computeBasePremium(step.items);
115	  const surcharges = sumItemSurcharges(step.items) + sumPolicySurcharges(base);
116	  const discounts = sumPolicyDiscounts(base, ctx);
117	  return {
118	    premium: Math.ceil(base + surcharges - discounts + PROCESSING_FEE),
119	  };
120	};
121	
122	export const runScenario = (scenario: unknown): unknown => {
123	  const { customer, steps } = scenario as Scenario;
124	  let contractIndex = 0;
125	  const policies = new Map<number, Item[]>();
126	  const results = steps.map((step, index) => {
127	    if (step.op === "claim") {
128	      const policyItems = policies.get(step.policy) ?? [];
129	      return claimStep(step, policyItems);
130	    }
131	    policies.set(index, step.items);
132	    const result = quoteStep(step, { customer, contractIndex });
133	    contractIndex += 1;
134	    return result;
135	  });
136	  return { results };
137	};
